#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: Azure Managed Service Identity (MSI)
 *
 * Description: Use Azure Managed Identity for applications running in Azure.
 * No secrets needed!
 *
 * Prerequisites:
 * - Application running in Azure (VM, App Service, Function, etc.)
 * - Managed Identity enabled and assigned to the resource
 * - Managed Identity has permissions to Databricks workspace
 *
 * Setup:
 * 1. Enable system-assigned or user-assigned managed identity on Azure resource
 * 2. Grant the managed identity permissions to Databricks workspace
 * 3. For user-assigned identity, get the client ID
 *
 * Run (on Azure resource):
 * ```bash
 * DATABRICKS_HOST="https://adb-<workspace-id>.<random>.azuredatabricks.net" \
 * DATABRICKS_AZURE_CLIENT_ID="<managed-identity-client-id>" \
 * npx ts-node examples/auth/azure-msi.ts
 * ```
 *
 * For system-assigned identity, you can omit DATABRICKS_AZURE_CLIENT_ID
 */

import {Config, WorkspaceClient} from "@databricks/sdk-experimental";

async function main() {
    const config = new Config({
        host: process.env.DATABRICKS_HOST,
        azureClientId: process.env.DATABRICKS_AZURE_CLIENT_ID, // Optional for system-assigned MSI
    });

    const client = new WorkspaceClient(config);

    try {
        const user = await client.currentUser.me();
        console.log(
            `✓ Successfully authenticated via Azure MSI as: ${user.userName}`
        );
        console.log(`  User ID: ${user.id}`);

        console.log(`  Host: ${config.host}`);
        if (config.azureClientId) {
            console.log(
                `  Managed Identity Client ID: ${config.azureClientId}`
            );
        } else {
            console.log(`  Using system-assigned managed identity`);
        }
    } catch (error) {
        console.error("✗ Authentication failed:", error);
        console.error("\nMake sure:");
        console.error(
            "  1. This code is running on an Azure resource (VM, App Service, etc.)"
        );
        console.error("  2. Managed Identity is enabled on the resource");
        console.error(
            "  3. Managed Identity has permissions to Databricks workspace"
        );
        console.error("  4. DATABRICKS_HOST environment variable is set");
        process.exit(1);
    }
}

main().catch(console.error);
